#define BUFFER_SIZE 1024
#define IP "192.168.1.104"
#define PORT 8000

void *sendData(void *arg);
void receiveData(int socket);

int main(int argc, char *argv[]){
	int socket = socket(AF_INET, SOCK_STREAM, 0);
	struct sockaddr_in server;
	server.sin_family = AF_INET;
	server.sin_port = htons(PORT);
	server.sin_addr.s_addr = inet_addr(IP);
	if(connect(socket,(struct sockaddr *)&server,sizeof(server)) == -1){
		perror("connect");
		exit(0);
	}
	pthread_t thread;
	pthread_create(&thread, NULL, sendData, (void *)&socket);
	receiveData(socket);
}

void *sendData(void *arg){
	int *socket = (int *)arg;
	char buffer[BUFFER_SIZE];
	int len;
	while(1){
		len = read(STDIN_FILENO, buffer, BUFFER_SIZE);
		if(len <= 0)
			break;
		write(*socket, buffer, len);
	}
}

void receiveData(int socket){
	char buffer[BUFFER_SIZE];
	int len;
	while(1){
		len = read(socket, buffer, BUFFER_SIZE);
		if(len <= 0)
			break;
		write(STDOUT_FILENO, buffer, len);
	}
}
